import moment from "moment";
import type { IPaginationRequest } from "@lmb-it/kitsconcerto-types";

/**
 * Detects whether a string value looks like a date in common formats
 * and converts it to a Date object. Returns the original value otherwise.
 * Pure function — no side-effects, safe to use on native.
 */
export function valueChecker(value: unknown): Date | unknown {
    if (typeof value !== "string") {
        return value;
    }

    const formats = [
        "YYYY-MM-DDTHH:mm:ss.SSSSSSZ",
        "YYYY-MM-DD",
        "DD/MM/YYYY hh:mm:ss A",
        "YYYY-MM-DD HH:mm:ss",
    ];

    for (let i = 0; i < formats.length; i++) {
        const m = moment(value, formats[i]!, true);
        if (m.isValid()) {
            return m.toDate();
        }
    }

    return value;
}

/**
 * Converts raw row objects so that date-looking string values become
 * actual Date instances (for PrimeReact column type=date filters).
 */
export function fixData<T extends Record<string, any>>(data: T[]): T[] {
    return [...(data || [])].map((d) => {
        const row: Record<string, any> = {};
        Object.entries(d).forEach(([key, value]) => {
            row[key] = valueChecker(value);
        });
        return row as T;
    });
}

/**
 * Converts Date instances inside filter values back to ISO strings
 * before sending them to the server-side service.
 */
export function revertFilter(
    filters: IPaginationRequest["filters"],
): Record<string, unknown> {
    const row: Record<string, unknown> = {};
    const ff = "YYYY-MM-DD\\THH:mm:ss.000\\Z";

    Object.entries(filters).forEach(([key, value]) => {
        if ("value" in value && value.value instanceof Date) {
            row[key] = {
                ...value,
                value: moment(value.value).format(ff),
            };
        } else {
            row[key] = value;
        }
    });

    return row;
}
